module priority_encoder_8bit
(
    input [7:0] obf_i,
    output reg [2:0] y,
    output reg valid
);

always @(*) begin
    valid = |obf_i;
    if (obf_i[7]) y = 3'b111;
    else if (obf_i[6]) y = 3'b110;
    else if (obf_i[5]) y = 3'b101;
    else if (obf_i[4]) y = 3'b100;
    else if (obf_i[3]) y = 3'b011;
    else if (obf_i[2]) y = 3'b010;
    else if (obf_i[1]) y = 3'b001;
    else if (obf_i[0]) y = 3'b000;
    else y = 3'b000;
end

endmodule
